        'owner': props.get('Owner'),
        'status': props.get('Status'),
        'area': props.get('Area'),
        'needs_gustavo': props.get('Needs Gustavo'),
        'next_check': props.get('Next check'),
        'next_step': props.get('Next step'),
        'edited': page.get('last_edited_time'),
        'notes': props.get('Notes'),
    })

active=[r for r in rows if r['status'] not in ('Done', None)]
